import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.sql.ResultSet;
import java.sql.ResultSetMetaData;
import java.sql.SQLException;

import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private ResultSet resultSetMock;
    private ResultSetMetaData metaDataMock;

    @BeforeEach
    void setUp() {
        resultSetMock = mock(ResultSet.class);
        metaDataMock = mock(ResultSetMetaData.class);
    }

    @Test
    void testWithHeader_withNonNullResultSet() throws SQLException {
        when(resultSetMock.getMetaData()).thenReturn(metaDataMock);
        CSVFormat baseFormat = CSVFormat.DEFAULT;

        CSVFormat result = baseFormat.withHeader(resultSetMock);

        assertNotNull(result);
        verify(resultSetMock).getMetaData();
    }

    @Test
    void testWithHeader_withNullResultSet() throws SQLException {
        CSVFormat baseFormat = CSVFormat.DEFAULT;

        CSVFormat result = baseFormat.withHeader((ResultSet) null);

        assertNotNull(result);
    }

    @Test
    void testWithHeader_withMetaDataThrowsSQLException() throws SQLException {
        when(resultSetMock.getMetaData()).thenThrow(new SQLException("MetaData error"));

        assertThrows(SQLException.class, () -> CSVFormat.DEFAULT.withHeader(resultSetMock));
    }
}
